import React, { useState } from 'react';
import { 
  Users, Bell, Home, LogOut, 
  Zap, CheckCircle2, ArrowLeft, 
  Download, Clock, Filter, TrendingUp, AlertCircle
} from 'lucide-react';

/**
 * HOMELY - INTEGRATED PROPERTY MANAGEMENT SYSTEM
 * * Features included:
 * - Role-based Dashboard (Resident/Landlord)
 * - Automatic Electricity Calculation (Units * Price)
 * - 5-Day Grace Period Late Fee Logic
 * - Landlord Approval/Rejection Queue
 * - Financial Statistics Tracking
 */

const App = () => {
  const [userRole, setUserRole] = useState(null); 
  const [loginMode, setLoginMode] = useState('tenant'); 
  const [activeTab, setActiveTab] = useState('Dashboard');

  // --- Central Data Management ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'Pending', 
      amount: 12500, 
      dueDate: '2026-04-05', 
      prevReading: 1020,
      currReading: 1150,
      unitPrice: 8,
      lateFeePerDay: 50,
      history: [
        { month: 'March', amount: 13200, status: 'Paid', date: '02/03/2026' }
      ]
    },
    { 
      id: 2, 
      name: 'Anita Sharma', 
      room: 'B-204', 
      status: 'Pending Approval', 
      amount: 15000, 
      dueDate: '2026-04-05', 
      prevReading: 500, 
      currReading: 580, 
      unitPrice: 8, 
      lateFeePerDay: 50,
      history: []
    },
  ]);

  // --- Core Utility Logic ---
  const calculateElectricity = (t) => (t.currReading - t.prevReading) * t.unitPrice;

  const calculateLateFee = (t) => {
    const due = new Date(t.dueDate);
    const today = new Date();
    const diffTime = today - due;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    // Apply fee only after 5-day grace period
    return diffDays > 5 ? (diffDays - 5) * t.lateFeePerDay : 0;
  };

  const getTotalPayable = (t) => t.amount + calculateElectricity(t) + calculateLateFee(t);

  const handleLandlordAction = (tenantId, action) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        if (action === 'approve') {
          return { 
            ...t, 
            status: 'Paid',
            history: [{ month: 'Current', amount: getTotalPayable(t), status: 'Paid', date: new Date().toLocaleDateString() }, ...t.history]
          };
        }
        return { ...t, status: 'Pending' };
      }
      return t;
    }));
  };

  // --- Auth Screen ---
  if (!userRole) {
    return (
      <div className="min-h-screen bg-[#0F172A] flex items-center justify-center p-4">
        <div className="w-full max-w-4xl bg-white rounded-[3rem] overflow-hidden shadow-2xl grid grid-cols-1 md:grid-cols-2">
          <div className="bg-slate-900 p-16 text-white flex flex-col justify-between hidden md:flex">
            <div className="flex items-center gap-3 italic font-black text-2xl">
              <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic">H</div> Homely
            </div>
            <h1 className="text-5xl font-black leading-tight italic">Manage Your<br/>Property.<br/>Better.</h1>
            <p className="text-slate-500 font-bold uppercase tracking-widest text-xs italic">Smart Management System</p>
          </div>
          <div className="p-8 md:p-16 flex flex-col justify-center">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl mb-10">
              <button onClick={() => setLoginMode('tenant')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'tenant' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Resident</button>
              <button onClick={() => setLoginMode('admin')} className={`flex-1 py-4 rounded-xl text-[10px] font-black uppercase transition-all ${loginMode === 'admin' ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-400'}`}>Landlord</button>
            </div>
            <form onSubmit={(e) => {e.preventDefault(); setUserRole(loginMode); setActiveTab(loginMode === 'admin' ? 'Dashboard' : 'Overview');}} className="space-y-4">
              <input type="text" placeholder="Mobile / ID" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <input type="password" placeholder="Password" className="w-full bg-slate-50 border-none rounded-2xl py-5 px-8 font-black outline-none" required />
              <button className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl uppercase tracking-[0.2em] text-xs shadow-2xl hover:bg-indigo-600 transition-all">Sign In</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} activeTab={activeTab} setActiveTab={setActiveTab} onAction={handleLandlordAction} logout={() => setUserRole(null)} calcTotal={getTotalPayable} />
  ) : (
    <TenantPortal tenant={tenants[0]} logout={() => setUserRole(null)} calcElec={calculateElectricity} calcLate={calculateLateFee} calcTotal={getTotalPayable} />
  );
};

// --- Landlord View ---
const AdminPortal = ({ tenants, activeTab, setActiveTab, onAction, logout, calcTotal }) => {
  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 flex flex-col">
        <div className="flex items-center gap-3 font-black italic text-xl mb-12">H Homely</div>
        <nav className="space-y-2 flex-1">
          {['Dashboard', 'Tenants'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full text-left px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeTab === tab ? 'bg-indigo-600' : 'text-slate-500'}`}>{tab}</button>
          ))}
        </nav>
        <button onClick={logout} className="w-full text-left px-6 py-4 text-red-500 text-[10px] font-black uppercase"><LogOut size={16} className="inline mr-2"/> Logout</button>
      </aside>

      <main className="flex-1 overflow-y-auto p-12">
        <header className="flex justify-between items-center mb-12">
          <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
          <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center border shadow-sm"><Bell size={20} className="text-slate-400"/></div>
        </header>

        {activeTab === 'Dashboard' && (
          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <StatCard label="Total Revenue" val={`₹${tenants.reduce((acc, t) => acc + (t.status === 'Paid' ? calcTotal(t) : 0), 0).toLocaleString()}`} icon={<TrendingUp/>} color="indigo"/>
              <StatCard label="Pending Approval" val={tenants.filter(t => t.status === 'Pending Approval').length} icon={<Clock/>} color="amber"/>
              <StatCard label="Unpaid Units" val={tenants.filter(t => t.status === 'Pending').length} icon={<AlertCircle/>} color="red"/>
            </div>

            <div className="bg-white rounded-[3rem] border shadow-sm overflow-hidden">
              <div className="p-10 border-b flex justify-between items-center">
                <h3 className="text-xs font-black uppercase italic">Resident Verification Queue</h3>
                <Filter size={16} className="text-slate-400"/>
              </div>
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase border-b">
                  <tr><th className="px-10 py-6">Resident</th><th className="px-10 py-6">Total Due</th><th className="px-10 py-6">Status</th><th className="px-10 py-6 text-right">Actions</th></tr>
                </thead>
                <tbody>
                  {tenants.map(t => (
                    <tr key={t.id} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                      <td className="px-10 py-6 font-bold text-xs">{t.name} ({t.room})</td>
                      <td className="px-10 py-6 font-bold text-xs">₹{calcTotal(t).toLocaleString()}</td>
                      <td className="px-10 py-6">
                        <span className={`px-4 py-1 rounded-full text-[8px] font-black uppercase ${t.status === 'Pending Approval' ? 'bg-amber-100 text-amber-600' : t.status === 'Paid' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100'}`}>{t.status}</span>
                      </td>
                      <td className="px-10 py-6 text-right">
                        {t.status === 'Pending Approval' && (
                          <div className="flex gap-2 justify-end">
                            <button onClick={() => onAction(t.id, 'approve')} className="bg-emerald-500 text-white px-4 py-2 rounded-lg text-[9px] font-black uppercase">Approve</button>
                            <button onClick={() => onAction(t.id, 'reject')} className="bg-red-50 text-red-500 px-4 py-2 rounded-lg text-[9px] font-black uppercase">Reject</button>
                          </div>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

const StatCard = ({ label, val, icon, color }) => (
  <div className="bg-white p-10 rounded-[2.5rem] border shadow-sm relative overflow-hidden">
    <div className={`absolute top-0 right-0 p-8 text-${color}-500/10`}>{icon}</div>
    <p className="text-[9px] font-black uppercase text-slate-400 mb-2 tracking-widest">{label}</p>
    <h3 className="text-3xl font-black italic">{val}</h3>
  </div>
);

// --- Resident View ---
const TenantPortal = ({ tenant, logout, calcElec, calcLate, calcTotal }) => {
  const [activeTab, setActiveTab] = useState('Overview');
  const electricity = calcElec(tenant);
  const lateFee = calcLate(tenant);
  const total = calcTotal(tenant);

  return (
    <div className="min-h-screen bg-[#FDFDFD] flex flex-col">
      <header className="h-24 bg-white border-b px-12 flex items-center justify-between sticky top-0 z-50">
         <div className="flex items-center gap-3 italic font-black text-xl text-indigo-600">MyHome</div>
         <nav className="flex gap-10">
            {['Overview', 'History'].map(t => (
               <button key={t} onClick={() => setActiveTab(t)} className={`text-[10px] font-black uppercase tracking-widest pb-1 border-b-2 transition-all ${activeTab === t ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent'}`}>{t}</button>
            ))}
            <button onClick={logout} className="text-[10px] font-black uppercase text-red-500">Sign Out</button>
         </nav>
      </header>

      <main className="p-12 max-w-6xl mx-auto w-full flex-1">
        {activeTab === 'Overview' && (
           <div className="space-y-12">
              <div className="bg-slate-900 rounded-[3.5rem] p-16 text-white shadow-2xl relative overflow-hidden">
                 <p className="text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest italic">Current Invoice • {tenant.room}</p>
                 <h2 className="text-7xl font-black tracking-tighter italic mb-8">₹{total.toLocaleString()}</h2>
                 
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12 border-t border-white/10 pt-8">
                    <div><p className="text-[9px] uppercase text-slate-500">Monthly Rent</p><p className="font-bold">₹{tenant.amount}</p></div>
                    <div><p className="text-[9px] uppercase text-slate-500">Electricity ({tenant.currReading - tenant.prevReading} units)</p><p className="font-bold">₹{electricity}</p></div>
                    {lateFee > 0 && <div><p className="text-[9px] uppercase text-red-400">Late Fee (Grace Period Over)</p><p className="font-bold text-red-400">₹{lateFee}</p></div>}
                 </div>

                 <div className={`inline-flex items-center gap-3 px-8 py-4 rounded-2xl font-black uppercase text-xs border ${tenant.status === 'Paid' ? 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30' : 'bg-slate-500/10 text-slate-400 border-white/10'}`}>
                    {tenant.status === 'Paid' ? <CheckCircle2 size={20}/> : <Clock size={20}/>} {tenant.status}
                 </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
                  <h4 className="text-[10px] font-black uppercase text-slate-400 mb-6 tracking-widest italic">Utility Tracking</h4>
                  <div className="flex justify-between items-center bg-slate-50 p-6 rounded-3xl">
                    <div><p className="text-[9px] font-black text-slate-400 uppercase">Prev. Meter</p><p className="text-xl font-bold">{tenant.prevReading}</p></div>
                    <Zap className="text-indigo-600 animate-pulse"/>
                    <div className="text-right"><p className="text-[9px] font-black text-slate-400 uppercase">Curr. Meter</p><p className="text-xl font-bold">{tenant.currReading}</p></div>
                  </div>
                </div>
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm flex items-center justify-between">
                  <div>
                    <h4 className="text-[10px] font-black uppercase text-slate-400 mb-1 tracking-widest italic">Lease Documents</h4>
                    <p className="text-xs font-bold">Standard_Agreement_2026.pdf</p>
                  </div>
                  <button className="p-4 bg-slate-100 rounded-2xl hover:bg-indigo-50 transition-colors"><Download size={20}/></button>
                </div>
              </div>
           </div>
        )}
      </main>
    </div>
  );
};

export default App;
